     5→//! Gallops JSON operations
     6→//!
     7→//! Implements read/write operations on the Gallops JSON store.
     8→//! All operations are atomic (write to temp, then rename).
     9→//!
    10→//! This module re-exports the public API from the new modular structure.
    11→
    12→use std::path::Path;
    13→
    14→// Re-export types
    15→pub use crate::jjrt_types::*;
    16→
    17→// Re-export validation
    18→pub use crate::jjrv_validate::jjrg_validate;
    19→
    20→// Re-export utilities
    21→pub use crate::jjru_util::{jjrg_capture_commit_sha, jjrg_make_tack, jjrg_read_stdin, jjrg_read_stdin_optional};
    22→
    23→// Re-export operations
    24→pub use crate::jjro_ops::{jjrg_nominate, jjrg_slate, jjrg_rail, jjrg_tally, jjrg_draft, jjrg_retire, jjrg_build_trophy_preview, jjrg_furlough, jjrg_garland};
    25→
    26→// Backwards compatibility: impl methods on jjrg_Gallops
    27→impl jjrg_Gallops {
    28→    /// Load Gallops from a file path (legacy API - prefer jjdr_load)
    29→    pub fn jjrg_load(path: &Path) -> Result<Self, String> {
    30→        use crate::jjri_io::jjdr_load;
    31→
    32→        // Use validated load, then unwrap to plain Gallops
    33→        jjdr_load(path).map(|vg| vg.into_inner())
    34→    }
    35→
    36→    /// Save Gallops to a file path (legacy API - prefer jjdr_save)
    37→    pub fn jjrg_save(&self, path: &Path) -> Result<(), String> {
    38→        use crate::jjri_io::jjdr_save;
    39→
    40→        jjdr_save(self, path)
    41→    }
    42→
    43→    /// Validate the Gallops structure
    44→    pub fn jjrg_validate(&self) -> Result<(), Vec<String>> {
    45→        jjrg_validate(self)
    46→    }
    47→
    48→    /// Nominate a new Heat
    49→    pub fn jjrg_nominate(&mut self, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
    50→        jjrg_nominate(self, args, base_path)
    51→    }
    52→
    53→    /// Slate a new Pace
    54→    pub fn jjrg_slate(&mut self, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
    55→        jjrg_slate(self, args)
    56→    }
    57→
    58→    /// Rail - reorder Paces within a Heat
    59→    pub fn jjrg_rail(&mut self, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
    60→        jjrg_rail(self, args)
    61→    }
    62→
    63→    /// Tally - add a new Tack to a Pace
    64→    pub fn jjrg_tally(&mut self, args: jjrg_TallyArgs) -> Result<(), String> {
    65→        jjrg_tally(self, args)
    66→    }
    67→
    68→    /// Draft - move a Pace from one Heat to another
    69→    pub fn jjrg_draft(&mut self, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
    70→        jjrg_draft(self, args)
    71→    }
    72→
    73→    /// Retire a Heat
    74→    pub fn jjrg_retire(
    75→        &mut self,
    76→        args: jjrg_RetireArgs,
    77→        base_path: &Path,
    78→        steeplechase: &[crate::jjrs_steeplechase::jjrs_SteeplechaseEntry],
    79→    ) -> Result<jjrg_RetireResult, String> {
    80→        jjrg_retire(self, args, base_path, steeplechase)
    81→    }
    82→
    83→    /// Build trophy markdown preview (dry-run)
    84→    pub fn jjrg_build_trophy_preview(
    85→        &self,
    86→        firemark: &str,
    87→        paddock_content: &str,
    88→        today: &str,
    89→        steeplechase: &[crate::jjrs_steeplechase::jjrs_SteeplechaseEntry],
    90→    ) -> Result<String, String> {
    91→        jjrg_build_trophy_preview(self, firemark, paddock_content, today, steeplechase)
    92→    }
    93→
    94→    /// Furlough a Heat - change status or rename
    95→    pub fn jjrg_furlough(&mut self, args: jjrg_FurloughArgs) -> Result<(), String> {
    96→        jjrg_furlough(self, args)
    97→    }
    98→
    99→    /// Garland a Heat - celebrate completion and create continuation
   100→    pub fn jjrg_garland(&mut self, args: jjrg_GarlandArgs, base_path: &Path) -> Result<jjrg_GarlandResult, String> {
   101→        jjrg_garland(self, args, base_path)
   102→    }
   103→}
