   636→
   637→/// Build trophy markdown content
   638→fn zjjrg_build_trophy_content(
   639→    firemark_key: &str,
   640→    heat: &jjrg_Heat,
   641→    paddock_content: &str,
   642→    today: &str,
   643→    steeplechase: &[SteeplechaseEntry],
   644→) -> Result<String, String> {
   645→    let mut content = String::new();
   646→
   647→    // Header
   648→    content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
   649→    content.push_str(&format!("**Firemark:** {}\n", firemark_key));
   650→    content.push_str(&format!("**Created:** {}\n", heat.creation_time));
   651→    content.push_str(&format!("**Retired:** {}\n", today));
   652→    content.push_str("**Status:** retired\n\n");
   653→
   654→    // Paddock
   655→    content.push_str("## Paddock\n\n");
   656→    content.push_str(paddock_content);
   657→    if !paddock_content.ends_with('\n') {
   658→        content.push('\n');
   659→    }
   660→    content.push('\n');
   661→
   662→    // Paces (in order)
   663→    content.push_str("## Paces\n\n");
   664→    for coronet_key in &heat.order {
   665→        if let Some(pace) = heat.paces.get(coronet_key) {
   666→            // Get final state from most recent tack
   667→            let final_state = pace.tacks.first()
   668→                .map(|t| match t.state {
   669→                    jjrg_PaceState::Rough => "rough",
   670→                    jjrg_PaceState::Bridled => "bridled",
   671→                    jjrg_PaceState::Complete => "complete",
   672→                    jjrg_PaceState::Abandoned => "abandoned",
   673→                })
   674→                .unwrap_or("unknown");
   675→
   676→            let pace_silks = pace.tacks.first()
   677→                .map(|t| t.silks.as_str())
   678→                .unwrap_or("unknown");
   679→
   680→            content.push_str(&format!(
   681→                "### {} ({}) [{}]\n\n",
   682→                pace_silks, coronet_key, final_state
   683→            ));
   684→
   685→            // Tack history (newest first, as stored)
   686→            for tack in &pace.tacks {
   687→                let state_str = match tack.state {
   688→                    jjrg_PaceState::Rough => "rough",
   689→                    jjrg_PaceState::Bridled => "bridled",
   690→                    jjrg_PaceState::Complete => "complete",
   691→                    jjrg_PaceState::Abandoned => "abandoned",
   692→                };
   693→                content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
   694→                content.push_str(&tack.text);
   695→                if !tack.text.ends_with('\n') {
   696→                    content.push('\n');
   697→                }
   698→                if let Some(ref direction) = tack.direction {
   699→                    content.push_str(&format!("\n*Direction:* {}\n", direction));
   700→                }
   701→                content.push('\n');
   702→            }
   703→        }
   704→    }
   705→
   706→    // Steeplechase (newest first, as provided)
   707→    content.push_str("## Steeplechase\n\n");
   708→    if steeplechase.is_empty() {
   709→        content.push_str("(no entries)\n\n");
   710→    } else {
   711→        for entry in steeplechase {
   712→            // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
   713→            let identity = entry.coronet.as_deref().unwrap_or("Heat");
   714→            let action = entry.action.as_deref().unwrap_or("notch");
   715→            content.push_str(&format!(
   716→                "### {} - {} - {}\n\n",
   717→                entry.timestamp, identity, action
   718→            ));
   719→            content.push_str(&entry.subject);
   720→            if !entry.subject.ends_with('\n') {
   721→                content.push('\n');
   722→            }
   723→            content.push('\n');
   724→        }
   725→    }
   726→
   727→    Ok(content)
   728→}
   729→
   730→/// Furlough a Heat - change status or rename
   731→///
   732→/// Updates heat status (racing/stabled) and/or silks.
   733→/// At least one change must be requested.
   734→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
   735→    // Validate at least one option provided
   736→    if !args.racing && !args.stabled && args.silks.is_none() {
   737→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
   738→    }
   739→
   740→    // Validate racing/stabled mutual exclusivity
   741→    if args.racing && args.stabled {
   742→        return Err("Cannot specify both --racing and --stabled".to_string());
   743→    }
   744→
   745→    // Validate silks if provided
   746→    if let Some(ref silks) = args.silks {
   747→        if !zjjrg_is_kebab_case(silks) {
   748→            return Err(format!("silks must be kebab-case, got '{}'", silks));
   749→        }
   750→    }
   751→
   752→    // Parse and normalize firemark
   753→    let firemark = Firemark::jjrf_parse(&args.firemark)
   754→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   755→    let firemark_key = firemark.jjrf_display();
   756→
   757→    // Verify Heat exists and check status
   758→    {
   759→        let heat = gallops.heats.get(&firemark_key)
   760→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   761→
   762→        // Check not retired (terminal state)
   763→        if heat.status == jjrg_HeatStatus::Retired {
   764→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
   765→        }
   766→
   767→        // Validate racing/stabled request
   768→        if args.racing && heat.status == jjrg_HeatStatus::Racing {
   769→            return Err(format!("Heat '{}' is already racing", firemark_key));
   770→        }
   771→        if args.stabled && heat.status == jjrg_HeatStatus::Stabled {
   772→            return Err(format!("Heat '{}' is already stabled", firemark_key));
   773→        }
   774→    }
   775→
   776→    // Apply status change if requested
   777→    if args.racing {
   778→        // Set status to racing
   779→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
   780→
   781→        // Move heat to front of heats object (index 0) to prioritize it
   782→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
   783→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
   784→        }
   785→    } else if args.stabled {
   786→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
   787→    }
   788→
   789→    // Apply silks change if requested
   790→    if let Some(silks) = args.silks {
   791→        gallops.heats.get_mut(&firemark_key).unwrap().silks = silks;
   792→    }
   793→
   794→    Ok(())
   795→}
   796→
   797→/// Garland a Heat - celebrate completion and create continuation
   798→///
   799→/// Updates source heat silks to garlanded form and status to stabled.
   800→/// Creates new heat with continuation silks, status racing.
   801→/// Transfers actionable paces (rough/bridled) to new heat.
   802→/// Retains complete/abandoned paces in garlanded heat.
   803→pub fn jjrg_garland(gallops: &mut jjrg_Gallops, args: jjrg_GarlandArgs, base_path: &Path) -> Result<jjrg_GarlandResult, String> {
   804→    use crate::jjrc_core::jjrc_timestamp_from_env;
   805→    use crate::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
   806→
   807→    // Parse and normalize firemark
   808→    let firemark = Firemark::jjrf_parse(&args.firemark)
   809→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   810→    let firemark_key = firemark.jjrf_display();
   811→
   812→    // Verify source heat exists and extract needed data (avoid holding the borrow)
   813→    let (source_silks, source_paddock_file, source_order, actionable_count, retained_count) = {
   814→        let source_heat = gallops.heats.get(&firemark_key)
   815→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   816→
   817→        // Parse source silks to determine sequence
   818→        let (base, sequence) = jjrq_parse_silks_sequence(&source_heat.silks);
   819→        let seq = sequence.unwrap_or(1);
   820→
   821→        // Count actionable paces
   822→        let actionable_count = source_heat.order.iter().filter(|coronet_key| {
   823→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   824→                if let Some(tack) = pace.tacks.first() {
   825→                    matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   826→                } else {
   827→                    false
   828→                }
   829→            } else {
   830→                false
   831→            }
   832→        }).count();
   833→
   834→        // Validate there are actionable paces to transfer
   835→        if actionable_count == 0 {
   836→            return Err(format!("Heat '{}' has no actionable paces to transfer", firemark_key));
   837→        }
   838→
   839→        // Count retained paces
   840→        let retained_count = source_heat.paces.len() - actionable_count;
   841→
   842→        // Count complete paces for steeplechase marker
   843→        let complete_count = source_heat.order.iter().filter(|coronet_key| {
   844→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
   845→                if let Some(tack) = pace.tacks.first() {
   846→                    tack.state == jjrg_PaceState::Complete
   847→                } else {
   848→                    false
   849→                }
   850→            } else {
   851→                false
   852→            }
   853→        }).count();
   854→
   855→        // Create steeplechase marker entry
   856→        let marker_text = format!("Garlanded at pace {} — magnificent service", complete_count);
   857→
   858→        // Update source heat: add steeplechase marker (prepend to paddock file)
   859→        let source_paddock_path = base_path.join(&source_heat.paddock_file);
   860→        let existing_content = std::fs::read_to_string(&source_paddock_path)
   861→            .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   862→
   863→        let updated_content = format!("{}\n\n{}", marker_text, existing_content);
   864→        std::fs::write(&source_paddock_path, updated_content)
   865→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   866→
   867→        ((base, seq), source_heat.paddock_file.clone(), source_heat.order.clone(), actionable_count, retained_count)
   868→    };
   869→
   870→    // Build garlanded and continuation silks
   871→    let (base, seq) = source_silks;
   872→    let garlanded_silks = jjrq_build_garlanded_silks(&base, seq);
   873→    let continuation_silks = jjrq_build_continuation_silks(&base, seq + 1);
   874→
   875→    // Nominate new heat with continuation silks
   876→    let created_ts = jjrc_timestamp_from_env();
   877→    let nominate_args = jjrg_NominateArgs {
   878→        silks: continuation_silks.clone(),
   879→        created: created_ts,
   880→    };
   881→    let nominate_result = jjrg_nominate(gallops, nominate_args, base_path)?;
   882→    let new_firemark_key = nominate_result.firemark.clone();
   883→
   884→    // Get destination heat paddock file for copy
   885→    let dest_paddock_file = {
   886→        let dest_heat = gallops.heats.get(&new_firemark_key)
   887→            .ok_or_else(|| "Failed to retrieve newly nominated heat".to_string())?;
   888→        dest_heat.paddock_file.clone()
   889→    };
   890→
   891→    // Read original paddock content before modifications (for new heat)
   892→    let source_paddock_path = base_path.join(&source_paddock_file);
   893→    let original_paddock_content = std::fs::read_to_string(&source_paddock_path)
   894→        .map_err(|e| format!("Failed to read paddock file: {}", e))?;
   895→
   896→    // Extract original content (removing marker we just added)
   897→    let existing_content = original_paddock_content.split_once("\n\n")
   898→        .map(|(_, rest)| rest)
   899→        .unwrap_or(&original_paddock_content);
   900→
   901→    // Copy paddock content from source to new heat
